import{_ as t,o as r,c as n,a4 as e}from"./chunks/framework.BDOgl-CJ.js";const m=JSON.parse('{"title":"BatchNorm 与 LayerNorm","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/batchnorm-layernorm.md","filePath":"ai-learning-notes/batchnorm-layernorm.md","lastUpdated":1779177473000}'),s={name:"ai-learning-notes/batchnorm-layernorm.md"};function o(d,a,l,i,h,p){return r(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="batchnorm-与-layernorm" tabindex="-1">BatchNorm 与 LayerNorm <a class="header-anchor" href="#batchnorm-与-layernorm" aria-label="Permalink to &quot;BatchNorm 与 LayerNorm&quot;">​</a></h1><h2 id="都是归一化" tabindex="-1">都是归一化 <a class="header-anchor" href="#都是归一化" aria-label="Permalink to &quot;都是归一化&quot;">​</a></h2><p>两者都是把数据变成「均值 0、方差 1」的标准形态，让训练更稳定更快。</p><p>核心公式：归一化后 = (原始值 - 均值) / 标准差</p><h2 id="一句话区分" tabindex="-1">一句话区分 <a class="header-anchor" href="#一句话区分" aria-label="Permalink to &quot;一句话区分&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>BatchNorm</th><th>LayerNorm</th></tr></thead><tbody><tr><td>归一化方向</td><td>同一特征，跨样本</td><td>同一样本，跨特征</td></tr><tr><td>比喻</td><td>「张三的语文在全班排第几」</td><td>「张三的语文在自己各科里排第几」</td></tr><tr><td>依赖 batch</td><td>是，batch 太小会不稳定</td><td>否，单个样本也行</td></tr><tr><td>训练/推理</td><td>不一致（推理用全局统计量）</td><td>完全一致</td></tr><tr><td>适合</td><td>CNN</td><td>Transformer、RNN</td></tr><tr><td>不适合</td><td>序列模型、小 batch</td><td>CNN</td></tr></tbody></table><h2 id="直观例子" tabindex="-1">直观例子 <a class="header-anchor" href="#直观例子" aria-label="Permalink to &quot;直观例子&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        语文  数学  英语</span></span>
<span class="line"><span>张三    90    80    70</span></span>
<span class="line"><span>李四    60    95    85</span></span>
<span class="line"><span>王五    75    70    90</span></span>
<span class="line"><span>赵六    88    78    82</span></span>
<span class="line"><span></span></span>
<span class="line"><span>BatchNorm：竖着归一 → 语文列 4 个人一起算均值和方差</span></span>
<span class="line"><span>LayerNorm：横着归一 → 张三 3 门课自己算均值和方差</span></span></code></pre></div><h2 id="为什么-transformer-用-layernorm" tabindex="-1">为什么 Transformer 用 LayerNorm <a class="header-anchor" href="#为什么-transformer-用-layernorm" aria-label="Permalink to &quot;为什么 Transformer 用 LayerNorm&quot;">​</a></h2><ol><li><strong>推理时 token 逐个来</strong>：自回归模型一次只出一个 token，凑不出一批做 BatchNorm</li><li><strong>Padding 不影响</strong>：补 0 的 token 在 BatchNorm 里会拉低统计量，LayerNorm 每个样本独立算不受影响</li><li><strong>训练推理一致</strong>：不需要像 BatchNorm 那样维护全局 running mean/var</li></ol>`,10)])])}const b=t(s,[["render",o]]);export{m as __pageData,b as default};
